    23Ôćĺ	let currentIndex = 0;
    24Ôćĺ
    25Ôćĺ	async function processNext(): Promise<void> {
    26Ôćĺ		while (currentIndex < items.length) {
    27Ôćĺ			const index = currentIndex++;
    28Ôćĺ			const item = items[index];
    29Ôćĺ
    30Ôćĺ			if (item === undefined) {
    31Ôćĺ				continue;
    32Ôćĺ			}
    33Ôćĺ
    34Ôćĺ			try {
    35Ôćĺ				const result = await handler(item);
    36Ôćĺ				results.push(result);
    37Ôćĺ				onItemComplete?.(result, item);
    38Ôćĺ			} catch (error) {
    39Ôćĺ				errors.push({ error, index });
